local base_dir = "/files/"

local filename = ngx.var.arg_filename

if not filename or filename == "" then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error: filename parameter is required")
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

-- URI-decode the filename
filename = ngx.unescape_uri(filename)

-- Reject null bytes which can truncate strings in C-based file operations
if filename:find("\0") then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error: invalid filename")
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

-- Normalize the path: collapse multiple slashes, resolve . and ..
-- Split path into segments and resolve
local segments = {}
for segment in filename:gmatch("[^/]+") do
    if segment == ".." then
        -- Going up a directory - remove last segment if any
        if #segments > 0 then
            table.remove(segments)
        else
            -- Attempting to traverse above the base directory
            ngx.status = ngx.HTTP_FORBIDDEN
            ngx.say("Error: access denied")
            return ngx.exit(ngx.HTTP_FORBIDDEN)
        end
    elseif segment ~= "." and segment ~= "" then
        segments[#segments + 1] = segment
    end
end

-- Reconstruct the normalized relative path
local normalized = table.concat(segments, "/")

-- Reject empty path after normalization
if normalized == "" then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error: invalid filename")
    return ngx.exit(ngx.HTTP_BAD_REQUEST)
end

-- Build the full path using the base directory
local full_path = base_dir .. normalized

-- Resolve the real (canonical) path using realpath to handle symlinks
-- We use io.popen as a fallback since Lua doesn't have a built-in realpath
local handle = io.popen("realpath -e " .. "'" .. full_path:gsub("'", "'\\''") .. "' 2>/dev/null")
local resolved_path = nil
if handle then
    resolved_path = handle:read("*l")
    handle:close()
end

if not resolved_path or resolved_path == "" then
    ngx.status = ngx.HTTP_NOT_FOUND
    ngx.say("Error: file not found")
    return ngx.exit(ngx.HTTP_NOT_FOUND)
end

-- Also resolve the base directory to its canonical form
local base_handle = io.popen("realpath -e " .. "'" .. base_dir:gsub("'", "'\\''") .. "' 2>/dev/null")
local resolved_base = nil
if base_handle then
    resolved_base = base_handle:read("*l")
    base_handle:close()
end

if not resolved_base or resolved_base == "" then
    ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
    ngx.say("Error: server configuration error")
    return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
end

-- Ensure resolved_base ends with / for proper prefix matching
if resolved_base:sub(-1) ~= "/" then
    resolved_base = resolved_base .. "/"
end

-- Verify the resolved path is strictly within the base directory
if resolved_path:sub(1, #resolved_base) ~= resolved_base then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say("Error: access denied")
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end

-- Check that the resolved path points to a regular file (not a directory, device, etc.)
local attr_handle = io.popen("test -f " .. "'" .. resolved_path:gsub("'", "'\\''") .. "' && echo yes 2>/dev/null")
local is_file = nil
if attr_handle then
    is_file = attr_handle:read("*l")
    attr_handle:close()
end

if is_file ~= "yes" then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say("Error: not a regular file")
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end

-- Open and serve the file
local file, err = io.open(resolved_path, "rb")
if not file then
    ngx.status = ngx.HTTP_NOT_FOUND
    ngx.say("Error: file not found")
    return ngx.exit(ngx.HTTP_NOT_FOUND)
end

-- Read and serve in chunks to handle large files
